76	  });
77	
78	  describe("Quote - component premiums", () => {
79	    it("returns 30 G for a single rune (25 base + 5 fee)", () => {
80	      const result = processScenario({
81	        customer: { yearsWithMHPCO: 0 },
82	        steps: [
83	          {
84	            op: "quote" as const,
85	            items: [{ type: "rune" }],
86	          },
87	        ],
88	      });
89	      expect(result.results[0]).toEqual({ premium: 30 });
90	    });
91	    it.todo("returns 55 G for 2 runes (50 base + 5 fee)");
92	    it.todo("returns 65 G for 3 alike runes (60 block premium + 5 fee)");
93	    it.todo("returns 105 G for 4 runes (no block: 4 * 25 = 100 + 5 fee)");
94	    it.todo("returns 80 G for 2 runes + 1 moonstone (no block: different types, 75 + 5 fee)");
95	    it.todo("returns 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");
96	  });
97	
98	  describe("Quote - cursed surcharge", () => {
99	    it.todo("adds 50% surcharge to a cursed sword (100 + 50 + 5 fee = 155 G)");
100	    it.todo("applies cursed surcharge only to the cursed item in a multi-item policy");
101	  });
102	
103	  describe("Quote - high enchantment surcharge", () => {
104	    it.todo("adds 30% surcharge for enchantment level 5 (100 + 30 + 5 fee = 135 G)");
105	    it.todo("does not add surcharge for enchantment level 4");
106	    it.todo("applies both cursed and high enchantment surcharges to the same item");
107	  });
108	
109	  describe("Quote - loyalty discount", () => {
110	    it.todo("applies 20% loyalty discount for customer with 2 years");
111	    it.todo("does not apply loyalty discount for customer with 1 year");
112	  });
113	
114	  describe("Quote - first insurance surcharge", () => {
115	    it.todo("adds 10% first insurance surcharge on policy base premium");
116	  });
117	
118	  describe("Quote - follow-up contract discount", () => {
119	    it.todo("applies 15% follow-up discount on second quote in scenario");
120	  });
121	
122	  describe("Quote - rounding", () => {
123	    it.todo("rounds premium up in MHPCO's favor (ceiling)");
124	  });
125	
126	  describe("Quote - integration", () => {
127	    it.todo("newcomer with cursed sword: 165 G");
128	    it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");
129	  });
130	
131	  describe("Quote - errors", () => {
132	    it.todo("throws error for unknown item type");
133	  });
134	
135	  describe("Claim - basic payout", () => {
136	    it.todo("applies 100 G deductible per damaged item");
137	    it.todo("fully reimburses standard item damage minus deductible");
138	  });
139	
140	  describe("Claim - dragon material", () => {
141	    it.todo("fully reimburses damage to dragon material items minus deductible");
142	  });
143	
144	  describe("Claim - high enchantment reimbursement", () => {
145	    it.todo("reimburses 50% of damage for enchantment >= 8, then applies deductible");
146	    it.todo("50% rule wins over dragon material when enchantment >= 8");
147	  });
148	
149	  describe("Claim - cap", () => {
150	    it.todo("caps total payout at twice the insurance sum");
151	    it.todo("tracks remaining cap across multiple claims on same policy");
152	  });
153	
154	  describe("Claim - multiple damages in one event", () => {
155	    it.todo("applies deductible per damaged item in same event");
156	    it.todo("handles two damages of same item type when policy covers two");
157	  });
158	
159	  describe("Claim - payout rounding", () => {
160	    it.todo("rounds payout down in MHPCO's favor (floor)");
161	  });
162	
163	  describe("Claim - errors", () => {
164	    it.todo("rejects damage for item type not in policy");
165	    it.todo("rejects more damages of a type than policy covers");
166	    it.todo("rejects negative damage amount");
167	  });
168	});
