1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	const basePremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;
12	
13	const calculateQuotePremium = (items: any[]): number =>
14	  items.reduce((sum: number, item: any) => sum + basePremium(item), 0) + PROCESSING_FEE;
15	
16	export const processScenario = (scenario: any): any => {
17	  const results = scenario.steps.map((step: any) => ({
18	    premium: calculateQuotePremium(step.items),
19	  }));
20	  return { results };
21	};
22

